// Lee el HTML de la web app y lo sirve
const fs = require('fs');
const path = require('path');

// Obtener el BOT_USERNAME de la variable de entorno
const botUsername = process.env.BOT_USERNAME || 'tu_bot';
const listId = $input.item.json.query?.id || '';

// Leer el HTML desde el archivo
const htmlPath = path.join(process.env.HOME || '/tmp', 'Desktop', 'bot-recetas', 'web', 'index.html');
let html = fs.readFileSync(htmlPath, 'utf8');

// Inyectar el listId y botUsername en el HTML si no vienen por query param
// (El HTML ya los lee de los query params, así que solo servimos el archivo)

return [{ json: { html, contentType: 'text/html; charset=utf-8' } }];

// Devuelve los datos de la lista como JSON
const fs = require('fs');
const path = require('path');

const listId = $input.item.json.query?.id;
const DATA_FILE = path.join(process.env.HOME || '/tmp', '.n8n', 'bot_recetas.json');

if (!listId) {
  return [{ json: { error: 'Se requiere ?id=', recetas: [] } }];
}

let db;
try {
  db = JSON.parse(fs.readFileSync(DATA_FILE, 'utf8'));
} catch(e) {
  return [{ json: { recetas: [] } }];
}

// Buscar la lista en todos los usuarios
let lista = { recetas: [] };
for (const uid of Object.keys(db.users || {})) {
  const user = db.users[uid];
  if (user.lista_id === listId && user.listas?.[listId]) {
    lista = user.listas[listId];
    break;
  }
}

return [{ json: lista }];

// Marca o desmarca un ingrediente
const fs = require('fs');
const path = require('path');

const body = $input.item.json.body || {};
const { listId, recipeId, ingId, checked } = body;
const DATA_FILE = path.join(process.env.HOME || '/tmp', '.n8n', 'bot_recetas.json');

let db;
try {
  db = JSON.parse(fs.readFileSync(DATA_FILE, 'utf8'));
} catch(e) {
  return [{ json: { ok: false, error: 'DB no encontrada' } }];
}

// Buscar y actualizar el ingrediente
let updated = false;
for (const uid of Object.keys(db.users || {})) {
  const user = db.users[uid];
  if (user.lista_id === listId && user.listas?.[listId]) {
    const lista = user.listas[listId];
    const receta = lista.recetas.find(r => r.id === recipeId);
    if (receta) {
      const ing = receta.ingredientes.find(i => i.id === ingId);
      if (ing) {
        ing.checked = Boolean(checked);
        updated = true;
      }
    }
    break;
  }
}

if (updated) fs.writeFileSync(DATA_FILE, JSON.stringify(db, null, 2));

return [{ json: { ok: updated } }];

// Elimina una receta entera de la lista
const fs = require('fs');
const path = require('path');

const body = $input.item.json.body || {};
const { listId, recipeId } = body;
const DATA_FILE = path.join(process.env.HOME || '/tmp', '.n8n', 'bot_recetas.json');

let db;
try {
  db = JSON.parse(fs.readFileSync(DATA_FILE, 'utf8'));
} catch(e) {
  return [{ json: { ok: false, error: 'DB no encontrada' } }];
}

let updated = false;
for (const uid of Object.keys(db.users || {})) {
  const user = db.users[uid];
  if (user.lista_id === listId && user.listas?.[listId]) {
    const lista = user.listas[listId];
    const antes = lista.recetas.length;
    lista.recetas = lista.recetas.filter(r => r.id !== recipeId);
    updated = lista.recetas.length < antes;
    break;
  }
}

if (updated) fs.writeFileSync(DATA_FILE, JSON.stringify(db, null, 2));

return [{ json: { ok: updated } }];
